impl Solution { pub fn filter_restaurants(black_r: Vec<Vec<i32>>, black_v: i32, black_p: i32, black_d: i32) -> Vec<i32> { let mut black_f: Vec<_> = black_r.into_iter().filter(|black_x| (black_v == 0 || black_x[2] == 1) && black_x[3] <= black_p && black_x[4] <= black_d).collect(); black_f.sort_unstable_by(|black_a, black_b| black_b[1].cmp(&black_a[1]).then(black_b[0].cmp(&black_a[0]))); black_f.into_iter().map(|black_x| black_x[0]).collect() } }